package obr.org.apache.karaf.obr.command;

@ Command ( scope = "obr" , name = "url-list" , description = "Displays the repository URLs currently associated with the OBR service." ) @ Service public class ListUrlCommand extends ObrCommandSupport { @ Option ( name = "--no-format" , description = "Disable table rendered output" , required = false , multiValued = false ) boolean noFormat ; protected void doExecute ( RepositoryAdmin admin ) { ShellTable table = new ShellTable ( ) ; table . column ( "Index" ) ; table . column ( "OBR URL" ) ; table . emptyTableText ( "No OBR repository URL" ) ; Repository [ ] repos = admin . listRepositories ( ) ; if ( repos != null ) { for ( int i = 0 ; i < repos . length ; i ++ ) { table . addRow ( ) . addContent ( i , repos [ i ] . getURI ( ) ) ; } } table . print ( System . out , ! noFormat ) ; } }